LAYER
	NAME "catastro_minero_18s"
	GROUP "INGEMMET"
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	PROCESSING "CLUSTER_GET_ALL_SHAPES=ON"
	TOLERANCE 10
	UNITS PIXELS
	HEADER "plantillas/inicio.html"
	TEMPLATE "plantillas/allpa/sbn/predios.html"
	FOOTER "plantillas/fin.html"
	STATUS on
	DATA "geom FROM (SELECT gid, codigou, fec_denu, concesion, tit_conces, d_estado, carta, zona, leyenda, sustancia, depa, provi, distri, ROUND(hasdatum::numeric, 2) AS hasdatum, geom FROM ingemmet.catastro_minero_18s) as allpa using unique gid using srid=32718"
    FILTER ("[depa]" IN "CUSCO")
	INCLUDE "configuracion/postgresql_allpa.map"
	PROJECTION
		"init=epsg:32718"
	END
	CLASSITEM "gid"
	METADATA
		"wms_group_title" "INGEMMET"
		"queryable" "true"
		"wms_metadataurl_href" ""
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Catastro minero (18S)"
		"wms_abstract" "Catastro minero (18S) || Instituto Geológico, Minero y Metalúrgico - INGEMMET :: Perú"
		"wms_credit" "INGEMMET"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_extent" "163743.0499999998 8074000 826083.1100000003 9673000"
		"wms_srs" "EPSG:32718"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
		"wms_enable_request" "*"
	END
	CLASS
		NAME "Catastro minero (18S)"
		EXPRESSION /./
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 239 184 16
			WIDTH 1
		END
	END
END # Layer